/********************************************************************
 * UNIFIED ENGINE v4.0
 * + ANTI HALLUCINATION
 * + SAFE JSON EXTRACTION
 * + KB DETECTION
 * + AUTO REPAIR id_motivo/id_nomenclatura
 * + STRICT CLASSIFICATION VALIDATION
 ********************************************************************/

/* ===================== HELPERS ===================== */

function parseJSONLoose(v){ 
  if (!v) return null;

  if (typeof v === 'object') return v;

  try {
    return JSON.parse(v);
  } catch {}

  return null;
}

const num = (v, d=0) =>
  Number.isFinite(+v) ? +v : d;

/* ===================== TEXT NORMALIZER ===================== */

function normalizeText(txt=''){

  return String(txt)
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .trim();
}

/* ===================== SAFE JSON EXTRACTION ===================== */

function extractFirstJSONObject(text){

  if (!text || typeof text !== 'string') {
    return null;
  }

  text = text
    .replace(/```json/gi, '')
    .replace(/```/g, '')
    .trim();

  const start = text.indexOf('{');

  if (start === -1) return null;

  let depth = 0;
  let inString = false;
  let escaped = false;

  for (let i = start; i < text.length; i++) {

    const ch = text[i];

    if (escaped) {
      escaped = false;
      continue;
    }

    if (ch === '\\') {
      escaped = true;
      continue;
    }

    if (ch === '"') {
      inString = !inString;
      continue;
    }

    if (!inString) {

      if (ch === '{') depth++;

      if (ch === '}') {

        depth--;

        if (depth === 0) {
          return text.slice(start, i + 1);
        }
      }
    }
  }

  return null;
}

